// src/components/Carrito.js
import React, { useState } from 'react';
import { ShoppingBag, Truck, Store, AlertTriangle, Trash2, Plus, Minus, CreditCard } from 'lucide-react';
import { calcularEnvio } from '../utils/shippingService';

const Carrito = ({ cart, setCart, onCheckout, distanciaReal }) => {
  const [modoEntrega, setModoEntrega] = useState('delivery');
  const [paso, setPaso] = useState('revision');

  const costoEnvio = modoEntrega === 'delivery' ? calcularEnvio(distanciaReal) : 0;
  const totalProductos = cart.reduce((acc, p) => acc + Number(p.precioNuevo), 0);
  const totalPeso = cart.reduce((acc, p) => acc + Number(p.peso), 0);
  const totalFinal = totalProductos + costoEnvio;

  const itemsAgrupados = cart.reduce((acc, item) => {
    if (!acc[item.id]) acc[item.id] = { ...item, cantidad: 0 };
    acc[item.id].cantidad += 1;
    return acc;
  }, {});

  return (
    <div style={cartContainer}>
      <h3 style={title}><ShoppingBag size={20} color="#e67e22" /> Mi Carrito</h3>
      
      <div style={deliverySelector}>
        <button onClick={() => setModoEntrega('delivery')} style={modoEntrega === 'delivery' ? btnActive : btnInactive}><Truck size={14}/> Delivery</button>
        <button onClick={() => setModoEntrega('retiro')} style={modoEntrega === 'retiro' ? btnActive : btnInactive}><Store size={14}/> Retiro</button>
      </div>

      <div style={totalPeso > 15 ? errorBox : weightBox}>
        <AlertTriangle size={14} /> 
        <span>Peso: <strong>{totalPeso.toFixed(3)} kg</strong></span>
      </div>

      {paso === 'revision' ? (
        <>
          <div style={listStyle}>
            {Object.values(itemsAgrupados).map(item => (
              <div key={item.id} style={itemRow}>
                <div style={{flex: 1}}>
                  <div style={{fontWeight: 'bold', fontSize: '0.9rem'}}>{item.producto}</div>
                  <div style={{fontSize: '0.8rem', color: '#94a3b8'}}>${item.precioNuevo} x {item.cantidad}</div>
                </div>
                <Trash2 size={16} color="#ef4444" cursor="pointer" onClick={() => setCart(cart.filter(i => i.id !== item.id))} />
              </div>
            ))}
          </div>

          <div style={summaryBox}>
            {modoEntrega === 'delivery' && (
              <div style={summaryRow}>
                <span>Envío ({distanciaReal.toFixed(2)} km)</span>
                <span>${costoEnvio}</span>
              </div>
            )}
            <div style={{...summaryRow, fontWeight: 'bold', fontSize: '1.2rem', color: '#e67e22', marginTop: '10px'}}>
              <span>Total</span>
              <span>${totalFinal.toLocaleString()}</span>
            </div>
          </div>

          <button 
            disabled={modoEntrega === 'delivery' && totalPeso > 15}
            onClick={() => setPaso('pago')} 
            style={btnPrimario}
          >
            Pagar Pedido
          </button>
        </>
      ) : (
        <div style={{textAlign: 'center', padding: '20px 0'}}>
          <CreditCard size={40} color="#e67e22" style={{marginBottom: '10px'}} />
          <p>Total a debitar: <strong>${totalFinal}</strong></p>
          <button onClick={() => onCheckout(totalFinal)} style={btnPrimario}>Confirmar Pago</button>
          <button onClick={() => setPaso('revision')} style={btnVolver}>Cancelar</button>
        </div>
      )}
    </div>
  );
};

// Estilos (Asegúrate de incluirlos para que no de error)
const cartContainer = { background: 'white', padding: '20px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)' };
const title = { display: 'flex', alignItems: 'center', gap: '10px', marginTop: 0 };
const deliverySelector = { display: 'flex', background: '#f8fafc', padding: '5px', borderRadius: '12px', margin: '15px 0' };
const btnActive = { flex: 1, padding: '10px', border: 'none', background: '#1e293b', color: 'white', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '5px' };
const btnInactive = { flex: 1, background: 'none', border: 'none', color: '#64748b', cursor: 'pointer' };
const weightBox = { background: '#f0fdf4', color: '#166534', padding: '10px', borderRadius: '10px', fontSize: '0.8rem', display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '15px' };
const errorBox = { ...weightBox, background: '#fef2f2', color: '#991b1b' };
const listStyle = { borderTop: '1px solid #f1f5f9', padding: '15px 0' };
const itemRow = { display: 'flex', alignItems: 'center', marginBottom: '10px' };
const summaryBox = { borderTop: '2px dashed #f1f5f9', padding: '15px 0' };
const summaryRow = { display: 'flex', justifyContent: 'space-between', fontSize: '0.9rem' };
const btnPrimario = { width: '100%', padding: '15px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer' };
const btnVolver = { background: 'none', border: 'none', marginTop: '10px', color: '#94a3b8', cursor: 'pointer' };

export default Carrito;
